cases.baseline:
app.get('/user', (req, res) => {
  const q = `SELECT * FROM users WHERE id = ${req.query.id}`;
  db.query(q).then(rows => res.json(rows));
});

cases.with_skill:
app.get('/user', (req, res) => {
  db.query('SELECT * FROM users WHERE id = $1', [req.query.id])
    .then(rows => res.json(rows));
});

